css:
/* Showcase invoice styles — demonstrates @page rules, decorative class,
   tabular numbers, page break controls, etc. */

@page {
  size: A4;
  margin: 18mm 18mm 30mm 18mm;

  /* Seitenzahl gehört in den Footer — die obere Variante aus base.css aus. */
  @top-right { content: none; }

  /* Mehrzeilige Pflichtangaben, verankert oben im unteren Rand mit Abstand
     zur Blattkante. Seitenzahl mittig — alles auf einer Höhe. */
  @bottom-left {
    content: "Beispiel Handels GmbH \A Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Mustermann";
    font-size: 6.8pt; line-height: 1.45; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line;
    vertical-align: top; padding-top: 5mm;
  }
  @bottom-center {
    content: "Seite " counter(page) " von " counter(pages);
    font-size: 6.8pt; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; vertical-align: top; padding-top: 5mm;
  }
  @bottom-right {
    content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A Commerzbank Berlin · BIC COBADEFFXXX \A IBAN DE89 3704 0044 0532 0130 00 \A kontakt@example.com · +49 30 123456";
    font-size: 6.8pt; line-height: 1.45; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line;
    text-align: right; vertical-align: top; padding-top: 5mm;
  }
}

* { box-sizing: border-box; }

body {
  font-family: 'Helvetica', 'Arial', sans-serif;
  font-size: 10pt;
  line-height: 1.45;
  color: #111;
  margin: 0;
}

/* "decorative" elements get marked as PDF Artifact by WeasyPrint when
   role="presentation" is set; screen readers skip them. CSS just gives
   them their visual identity. */
/* Kein bunter Gradient-Balken mehr — die professionelle Akzentlinie sitzt
   als feine Unterkante des Briefkopfs (siehe .doc-header). */
hr.decorative {
  border: none;
  border-top: 1px solid #e5e7eb;
  margin: 8mm 0;
}

/* ───── Header ───── */
.doc-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12mm;
  /* Professionelle Akzentlinie: feine, kräftige Unterkante des Briefkopfs
     statt eines bunten Streifens — verankert Logo + Kontakt sauber. */
  border-bottom: 0.8pt solid #1f2937;
  padding-bottom: 5mm;
  margin-bottom: 7mm;
}
/* Brand nimmt die volle freie Breite, QR bleibt fix rechts — der
   Firmenname läuft so über die ganze Breite und bricht nicht um, auch
   wenn er etwas länger ist. */
.doc-header__brand {
  flex: 1 1 auto;
  min-width: 0;
}
.doc-header__brand .logo {
  display: block;
  max-width: 70mm;
  max-height: 18mm;
}
.doc-header__brand .logo--fallback {
  display: block;
  font-size: 16pt;
  letter-spacing: -0.01em;
  white-space: nowrap;
}
.doc-header__sender {
  font-size: 9pt;
  color: #6b7280;
  margin: 1mm 0 0;
}
.doc-header__vcard {
  flex: 0 0 auto;
  text-align: right;
}

/* QR boxes — fixed visual size so SVG inside scales nicely. */
.qr-label {
  display: block;
  font-size: 8pt;
  color: #6b7280;
  margin-bottom: 1mm;
}
.qr-box {
  width: 22mm;
  height: 22mm;
  display: inline-block;
  border: 1px solid #f1f5f9;
  padding: 1mm;
}
.qr-box--lg {
  width: 28mm;
  height: 28mm;
}
.qr-box svg {
  width: 100%;
  height: 100%;
  display: block;
}

/* ───── Recipient ───── */
.recipient {
  margin: 8mm 0 6mm;
}
.recipient__addr-line {
  font-size: 8pt;
  text-decoration: underline;
  color: #6b7280;
  margin: 0 0 2mm;
}
.recipient address {
  font-style: normal;
  font-size: 11pt;
  line-height: 1.5;
}

/* ───── Title + meta ───── */
.doc-title h1 {
  font-size: 18pt;
  font-weight: 600;
  margin: 0 0 3mm;
}
.meta {
  border-collapse: collapse;
  font-size: 9.5pt;
}
.meta th, .meta td { padding: 0.6mm 4mm 0.6mm 0; text-align: left; vertical-align: top; }
.meta th { font-weight: 500; color: #6b7280; }

/* ───── Positions table ───── */
.positions { margin-top: 8mm; }
.items {
  width: 100%;
  border-collapse: collapse;
  font-size: 9.5pt;
  font-variant-numeric: tabular-nums;
}
.items thead th {
  font-size: 8.5pt;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  text-align: left;
  padding: 2mm;
  border-bottom: 1px solid #1f2937;
  color: #1f2937;
}
.items thead th.num { text-align: right; }
.items tbody td {
  padding: 2.5mm 2mm;
  border-bottom: 1px solid #f1f5f9;
  vertical-align: top;
}
.items tbody td.num { text-align: right; }
.items tbody tr { page-break-inside: avoid; }
.item-desc { font-size: 9pt; color: #4b5563; margin: 0.5mm 0; }
.item-meta { font-size: 8pt; color: #9ca3af; font-family: ui-monospace, monospace; }
.barcode-cell svg { width: 22mm; height: 8mm; }
.muted { color: #9ca3af; }

/* ───── Totals ───── */
.totals {
  display: flex;
  justify-content: flex-end;
  margin-top: 4mm;
  page-break-inside: avoid;
}
.totals__table {
  border-collapse: collapse;
  min-width: 70mm;
  font-variant-numeric: tabular-nums;
}
.totals__table th, .totals__table td {
  padding: 1.5mm 0 1.5mm 4mm;
  text-align: right;
}
.totals__table th { font-weight: 500; color: #4b5563; }
.totals__table td.num { font-weight: 600; }
.totals__table tr.grand th,
.totals__table tr.grand td {
  border-top: 2px solid #1f2937;
  font-size: 12pt;
  font-weight: 700;
  padding-top: 2.5mm;
}

/* ───── Payment block ───── */
.payment {
  margin-top: 10mm;
  page-break-inside: avoid;
}
.payment h2 { font-size: 12pt; font-weight: 600; margin: 0 0 3mm; }
.payment__cols {
  display: flex;
  gap: 8mm;
  align-items: flex-start;
}
.payment__bank { flex: 1; }
.payment__bank dl { display: grid; grid-template-columns: 32mm 1fr; gap: 0.5mm 4mm; margin: 0; }
.payment__bank dt { color: #6b7280; font-size: 9pt; }
.payment__bank dd { margin: 0; font-size: 10pt; }
.payment__qr { text-align: right; }
.payment__qr small { display: block; font-size: 7.5pt; margin-top: 1mm; }

/* ───── Notes ───── */
.notes { margin-top: 8mm; page-break-inside: avoid; }
.notes h2 { font-size: 11pt; font-weight: 600; margin: 0 0 2mm; color: #374151; }

/* ───── Share / Beleg-Link ───── */
.share {
  margin-top: 10mm;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8mm;
  background: #f8fafc;
  border-radius: 2mm;
  padding: 4mm 5mm;
  page-break-inside: avoid;
}
.share h2 { font-size: 11pt; font-weight: 600; margin: 0 0 1mm; }
.share p { margin: 0; font-size: 9.5pt; }
.muted-url { font-family: ui-monospace, monospace; font-size: 8.5pt; color: #6b7280; word-break: break-all; }

/* ───── Doc code at the very bottom ───── */
.doc-code {
  margin-top: 8mm;
  text-align: center;
}
.doc-code svg { width: 60mm; height: 10mm; }
